using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ── DI & Chat-client pipeline ──────────────────────────────────────────────────
var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseFunctionInvocation(o => o.MaximumIterationsPerRequest = 10)
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();

// ── Tools ──────────────────────────────────────────────────────────────────────
var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync, "search_web",
        "Searches the web for a query and returns a list of result titles, URLs, and snippets. " +
        "Use this to find information about a research topic."),

    AIFunctionFactory.Create(notebook.SaveNote, "save_note",
        "Saves a research note with a title and body. " +
        "Use this to record key findings as you research."),

    AIFunctionFactory.Create(notebook.GetNotes, "get_notes",
        "Returns all saved research notes. " +
        "Use this to review what you have learned so far before writing a summary."),
};

// ── Agent ──────────────────────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Given a topic, you:
        1. Search the web for relevant information (make several varied searches).
        2. Save key findings as notes using the save_note tool.
        3. Review your notes with get_notes.
        4. Produce a concise, well-structured summary of your findings with source URLs.

        Be thorough — perform at least 3 different searches to cover the topic well.
        Always cite sources with their URLs.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and summarizing findings.",
    tools: tools);

// ── Run ────────────────────────────────────────────────────────────────────────
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(topic, session: null, runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n── Research Notes ────────────────────────────────────────");
foreach (var note in notebook.GetNotes())
{
    Console.WriteLine($"\n## {note.Title}\n{note.Body}\n");
}

// ════════════════════════════════════════════════════════════════════════════════
//  Tool implementations
// ════════════════════════════════════════════════════════════════════════════════

/// <summary>Searches the web using the DuckDuckGo Instant Answer API.</summary>
static async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
    [Description("The search query to look up on the web")] string query,
    CancellationToken cancellationToken = default)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

    var url = $"https://lite.duckduckgo.com/lite?q={Uri.EscapeDataString(query)}";
    var html = await http.GetStringAsync(url, cancellationToken);

    var results = ParseDuckDuckGoLite(html, maxResults: 5);

    if (results.Count == 0)
    {
        return [new SearchResult($"No results for: {query}",
            "https://duckduckgo.com/?q=" + Uri.EscapeDataString(query),
            "Try a different search query.")];
    }

    return results;
}

static List<SearchResult> ParseDuckDuckGoLite(string html, int maxResults)
{
    var results = new List<SearchResult>();

    // DDG Lite returns results in table rows with links and snippets
    var span = html.AsSpan();
    var searchIndex = 0;

    while (results.Count < maxResults)
    {
        // Find result links (class="result-link")
        var linkMarker = "class=\"result-link\"";
        var linkPos = html.IndexOf(linkMarker, searchIndex, StringComparison.OrdinalIgnoreCase);
        if (linkPos < 0) break;

        // Extract href
        var hrefStart = html.LastIndexOf("href=\"", linkPos, Math.Min(linkPos, 200), StringComparison.OrdinalIgnoreCase);
        if (hrefStart < 0) { searchIndex = linkPos + 1; continue; }
        hrefStart += 6;
        var hrefEnd = html.IndexOf('"', hrefStart);
        if (hrefEnd < 0) { searchIndex = linkPos + 1; continue; }
        var href = html[hrefStart..hrefEnd];

        // Extract title (text inside the <a> tag)
        var titleStart = html.IndexOf('>', linkPos) + 1;
        var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.OrdinalIgnoreCase);
        var title = titleEnd > titleStart
            ? StripHtmlTags(html[titleStart..titleEnd]).Trim()
            : "Untitled";

        // Extract snippet (next <td class="result-snippet">)
        var snippetMarker = "class=\"result-snippet\"";
        var snippetPos = html.IndexOf(snippetMarker, titleEnd > 0 ? titleEnd : linkPos + 1, StringComparison.OrdinalIgnoreCase);
        var snippet = "";
        if (snippetPos >= 0)
        {
            var snipStart = html.IndexOf('>', snippetPos) + 1;
            var snipEnd = html.IndexOf("</td>", snipStart, StringComparison.OrdinalIgnoreCase);
            if (snipEnd > snipStart)
            {
                snippet = StripHtmlTags(html[snipStart..snipEnd]).Trim();
            }
        }

        if (!string.IsNullOrWhiteSpace(title) && href.StartsWith("http", StringComparison.OrdinalIgnoreCase))
        {
            results.Add(new SearchResult(title, href, snippet));
        }

        searchIndex = snippetPos > 0 ? snippetPos + 1 : linkPos + 1;
    }

    return results;
}

static string StripHtmlTags(string input)
{
    var output = new System.Text.StringBuilder(input.Length);
    var inTag = false;
    foreach (var c in input)
    {
        if (c == '<') { inTag = true; continue; }
        if (c == '>') { inTag = false; continue; }
        if (!inTag) output.Append(c);
    }
    return System.Net.WebUtility.HtmlDecode(output.ToString());
}

// ════════════════════════════════════════════════════════════════════════════════
//  Types
// ════════════════════════════════════════════════════════════════════════════════

record SearchResult(string Title, string Url, string Snippet);

record Note(string Title, string Body);

/// <summary>Simple in-memory notebook for recording research findings.</summary>
sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a title and body text.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The body text of the note with the finding details")] string body)
    {
        _notes.Add(new Note(title, body));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Returns all saved research notes.")]
    public IReadOnlyList<Note> GetNotes() => _notes.AsReadOnly();
}

