141.         var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.OrdinalIgnoreCase);
142.         var title = titleEnd > titleStart
143.             ? StripHtmlTags(html[titleStart..titleEnd]).Trim()
144.             : "Untitled";
145. 
146.         // Extract snippet (next <td class="result-snippet">)
147.         var snippetMarker = "class=\"result-snippet\"";
148.         var snippetPos = html.IndexOf(snippetMarker, titleEnd > 0 ? titleEnd : linkPos + 1, StringComparison.OrdinalIgnoreCase);
149.         var snippet = "";
150.         if (snippetPos >= 0)
151.         {
152.             var snipStart = html.IndexOf('>', snippetPos) + 1;
153.             var snipEnd = html.IndexOf("</td>", snipStart, StringComparison.OrdinalIgnoreCase);
154.             if (snipEnd > snipStart)
155.             {
156.                 snippet = StripHtmlTags(html[snipStart..snipEnd]).Trim();
157.             }
158.         }
159. 
