 /// <summary>Searches the web using the DuckDuckGo Instant Answer API.</summary>
 static async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
     [Description("The search query to look up on the web")] string query,
     CancellationToken cancellationToken = default)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     using var http = new HttpClient();
     http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

     var url = $"https://lite.duckduckgo.com/lite?q={Uri.EscapeDataString(query)}";
     var html = await http.GetStringAsync(url, cancellationToken);

     var results = ParseDuckDuckGoLite(html, maxResults: 5);

     if (results.Count == 0)
     {
         return [new SearchResult($"No results for: {query}",
             "https://duckduckgo.com/?q=" + Uri.EscapeDataString(query),
             "Try a different search query.")];
     }

     return results;
 }

 static List<SearchResult> ParseDuckDuckGoLite(string html, int maxResults)
 {
     var results = new List<SearchResult>();

     // DDG Lite returns results in table rows with links and snippets
     var span = html.AsSpan();
     var searchIndex = 0;

     while (results.Count < maxResults)
     {
         // Find result links (class="result-link")
         var linkMarker = "class=\"result-link\"";
         var linkPos = html.IndexOf(linkMarker, searchIndex, StringComparison.OrdinalIgnoreCase);
         if (linkPos < 0) break;

         // Extract href
         var hrefStart = html.LastIndexOf("href=\"", linkPos, Math.Min(linkPos, 200), StringComparison.OrdinalIgnoreCase);
         if (hrefStart < 0) { searchIndex = linkPos + 1; continue; }
         hrefStart += 6;
         var hrefEnd = html.IndexOf('"', hrefStart);
         if (hrefEnd < 0) { searchIndex = linkPos + 1; continue; }
         var href = html[hrefStart..hrefEnd];

         // Extract title (text inside the <a> tag)
         var titleStart = html.IndexOf('>', linkPos) + 1;
         var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.OrdinalIgnoreCase);
         var title = titleEnd > titleStart
             ? StripHtmlTags(html[titleStart..titleEnd]).Trim()
             : "Untitled";

         // Extract snippet (next <td class="result-snippet">)
         var snippetMarker = "class=\"result-snippet\"";
         var snippetPos = html.IndexOf(snippetMarker, titleEnd > 0 ? titleEnd : linkPos + 1, StringComparison.OrdinalIgnoreCase);
         var snippet = "";
         if (snippetPos >= 0)
         {
             var snipStart = html.IndexOf('>', snippetPos) + 1;
             var snipEnd = html.IndexOf("</td>", snipStart, StringComparison.OrdinalIgnoreCase);
             if (snipEnd > snipStart)
             {
                 snippet = StripHtmlTags(html[snipStart..snipEnd]).Trim();
             }
         }

         if (!string.IsNullOrWhiteSpace(title) && href.StartsWith("http", StringComparison.OrdinalIgnoreCase))
         {
             results.Add(new SearchResult(title, href, snippet));
         }

         searchIndex = snippetPos > 0 ? snippetPos + 1 : linkPos + 1;
     }

     return results;
 }

 static string StripHtmlTags(string input)
 {
     var output = new System.Text.StringBuilder(input.Length);
     var inTag = false;
     foreach (var c in input)
     {
         if (c == '<') { inTag = true; continue; }
         if (c == '>') { inTag = false; continue; }
         if (!inTag) output.Append(c);
     }
     return System.Net.WebUtility.HtmlDecode(output.ToString());
 }

